const stdout = items[0].json.stdout || "";
const sections = stdout.split("===");
const reports = [];

for (let i = 1; i < sections.length; i += 2) {
  const host = sections[i].trim();
  const content = sections[i+1] ? sections[i+1].trim() : "";

  if (content === "OFFLINE" || !content) {
    continue;
  }

  const lines = content.split("\n");
  const dataLine = lines.find(line => line.includes("/") || line.includes("tmpfs") || line.match(/^\/dev\//) || line.split(/\s+/).length >= 6 && line !== lines[0]);
  if (dataLine) {
    const parts = dataLine.trim().split(/\s+/);
    if (parts.length >= 6) {
      reports.push({
        host,
        usage: parseInt(parts[4].replace("%", ""), 10),
        used: parts[2],
        size: parts[1]
      });
    }
  }
}

// We only filter for hosts with critical disk usage >= 90%
const criticalThreshold = 90;
const fullHosts = reports.filter(r => r.usage >= criticalThreshold);

return fullHosts.map(fh => ({
  json: {
    host: fh.host,
    usage: fh.usage + "%",
    used: fh.used,
    size: fh.size,
    shouldTrigger: true
  }
}));
